// Parse opp ownership CSV into per-person account lists with deal values
const csvData = $('Fetch Opp Ownership').first().json.data;
const userData = $('Workflow Input Trigger').first().json;

if (!csvData) {
  return [{ json: { ...userData, userAccounts: [], error: 'No ownership data' } }];
}

const lines = csvData.split('\n').filter(l => l.trim());
if (lines.length < 2) {
  return [{ json: { ...userData, userAccounts: [] } }];
}

function parseCsvLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuotes && i + 1 < line.length && line[i + 1] === '"') { current += '"'; i++; }
      else { inQuotes = !inQuotes; }
    } else if (ch === ',' && !inQuotes) {
      result.push(current.trim());
      current = '';
    } else {
      current += ch;
    }
  }
  result.push(current.trim());
  return result;
}

const headers = parseCsvLine(lines[0]);
const headerMap = {};
headers.forEach((h, i) => { headerMap[h.toLowerCase()] = i; });

function get(row, ...names) {
  for (const name of names) {
    const idx = headerMap[name.toLowerCase()];
    if (idx !== undefined && row[idx] !== undefined && row[idx] !== '') return row[idx];
  }
  return '';
}

// Build per-person account sets AND per-account max deal value
const accountsByPerson = {};  // person → Set of account names
const accountMaxAmount = {};  // account name → max deal amount

function addAccount(personName, accountName) {
  if (!personName || !accountName) return;
  const key = personName.toLowerCase().trim();
  if (!accountsByPerson[key]) accountsByPerson[key] = new Set();
  accountsByPerson[key].add(accountName);
}

for (let i = 1; i < lines.length; i++) {
  const row = parseCsvLine(lines[i]);
  if (row.length < 2) continue;

  const accountName = get(row, 'Account Name');
  const ownerName = get(row, 'Opportunity Owner (name)', 'Opportunity Owner');
  const csmName = get(row, 'CSM Owner (name)', 'CSM Owner');
  const amountStr = get(row, 'Amount (Converted)', 'Converted Amount', 'Amount');
  const amount = parseFloat(String(amountStr).replace(/[^0-9.\-]/g, '')) || 0;

  addAccount(ownerName, accountName);
  addAccount(csmName, accountName);

  // Track max deal value per account
  if (accountName) {
    accountMaxAmount[accountName] = Math.max(accountMaxAmount[accountName] || 0, amount);
  }
}

// Find this user's accounts
const scope = userData.digestScope || userData.digest_scope || 'my_deals';
const repName = userData.repName || '';
const repLower = repName.toLowerCase();

let userAccounts;
const MAX_ACCOUNTS = 30;

if (scope === 'my_deals') {
  // IC/CSM: only their accounts, sorted by deal value, capped
  const accts = accountsByPerson[repLower] ? Array.from(accountsByPerson[repLower]) : [];
  userAccounts = accts
    .sort((a, b) => (accountMaxAmount[b] || 0) - (accountMaxAmount[a] || 0))
    .slice(0, MAX_ACCOUNTS);
} else if (scope === 'team_deals') {
  // Manager: their accounts + reports (would need hierarchy data, fallback to own for now)
  const accts = accountsByPerson[repLower] ? Array.from(accountsByPerson[repLower]) : [];
  userAccounts = accts
    .sort((a, b) => (accountMaxAmount[b] || 0) - (accountMaxAmount[a] || 0))
    .slice(0, MAX_ACCOUNTS);
} else {
  // Exec/top_pipeline: all accounts with open opps, sorted by value, top 30
  const allAccounts = Object.keys(accountMaxAmount);
  userAccounts = allAccounts
    .sort((a, b) => (accountMaxAmount[b] || 0) - (accountMaxAmount[a] || 0))
    .slice(0, MAX_ACCOUNTS);
}

return [{ json: {
  ...userData,
  userAccounts,
  userAccountCount: userAccounts.length,
  totalAccountCount: Object.keys(accountMaxAmount).length
} }];

