}

const accountList = userAccounts.map(a => `• ${a}`).join('\n');

let scopeContext;
if (scope === 'my_deals') {
  scopeContext = `These are accounts where ${repName} is the owner or CSM.`;
} else if (scope === 'team_deals') {
  scopeContext = `These are your team's top accounts by deal value.`;
} else {
  scopeContext = `These are the top ${userAccounts.length} accounts by deal value (of ${totalAccountCount} total with open opportunities).`;
}

const prompt = `Check these specific accounts for engagement gaps. For each account below, check if there has been any customer-facing activity (emails, meetings, or calls) in the past 5 or more days. ${scopeContext}

${accountList}

Today's date is ${today}. Report any that have gone silent (5+ days with no activity).`;

const systemPrompt = `You are ${assistantName}, a proactive sales assistant.${assistantPersona ? ' Your personality: ' + assistantPersona + '.' : ''} You detect "silence contracts" — accounts where customer engagement has gone quiet.

Using the People.ai tools, check accounts for engagement gaps:
1. For each account, check the most recent customer-facing activity (emails, meetings, calls)
2. Identify accounts where the last activity was more than 5 days ago

Classify each silent account by severity:
- "info" (5-9 days): Getting quiet
- "warning" (10-20 days): Gone silent
- "critical" (21+ days): Relationship at risk

CRITICAL: End your response with a JSON code block:
\`\`\`json
{
  "silent_accounts": [
    {
      "account_name": "Account Name",
      "days_silent": 14,
      "last_activity_date": "2026-02-17",
      "last_activity_type": "email",
      "severity": "warning"
    }
  ]
}
\`\`\`
If no accounts are silent, return: \`\`\`json\n{"silent_accounts": []}\n\`\`\`
Do NOT include text after the JSON block.`;

return [{ json: { ...data, silencePrompt: prompt, systemPrompt, assistantName, assistantEmoji } }];

const agentOutput = $('Silence Agent').first().json.output || '';
const inputData = $('Build Silence Prompt').first().json;

// Get muted accounts
let allMuted = [];
try {
  allMuted = $('Fetch Muted Accounts').all().map(i => i.json);
} catch (e) {}

const now = new Date();
const userId = inputData.userId;
const mutedSet = new Set();
for (const m of allMuted) {
  if (m.user_id !== userId) continue;
  if (m.muted_until && new Date(m.muted_until) < now) continue;
  mutedSet.add((m.entity_name || '').toLowerCase());
}

// Extract JSON from agent response
let silentAccounts = [];
const jsonMatch = agentOutput.match(/```json\s*([\s\S]*?)\s*```/);
if (jsonMatch) {
  try {
    silentAccounts = JSON.parse(jsonMatch[1]).silent_accounts || [];
  } catch (e) {}
}

// Reclassify 60+ day accounts as 'dead'
for (const a of silentAccounts) {
  if ((a.days_silent || 0) >= 60) a.severity = 'dead';
}

// Filter out muted
const filtered = silentAccounts.filter(a => !mutedSet.has((a.account_name || '').toLowerCase()));

// Sort by severity then days
const order = { dead: 0, critical: 1, warning: 2, info: 3 };
filtered.sort((a, b) => (order[a.severity] || 9) - (order[b.severity] || 9) || (b.days_silent || 0) - (a.days_silent || 0));

// Dead accounts to auto-mute
const autoMuteAccounts = filtered
  .filter(a => a.severity === 'dead')
  .map(a => ({
    user_id: userId,
    organization_id: inputData.organizationId,
    alert_type_id: 'silence_contract',
    entity_name: a.account_name,
    mute_reason: 'auto_dead',
    muted_at: now.toISOString()
  }));

return [{ json: {
  ...inputData,
  silentAccounts: filtered,
  autoMuteAccounts,
  silentCount: filtered.length
} }];

